class Solution {
    public String gcdOfStrings(String str1, String str2) {
        if (str1 + str2.equals(str2 + str1)) {
            return gcd(str1, str2).toString();
        } else {
            return "";
        }
    }

    public StringBuilder gcd(String str1, String str2) {
        if (str2.isEmpty()) {
            return new StringBuilder(str1);
        }
        return gcd(str2, str1.substring(0, str2.length()));
    }
}
```

